func TestGzip(t *testing.T) {
	ziped := Gzip([]byte("123"))
	fmt.Println(len(ziped), ziped)

	ziped = Gzip([]byte("hgdtdt"))
	fmt.Println(len(ziped), ziped)

	ziped = Gzip([]byte("1"))
	fmt.Println(len(ziped), ziped)
}
